from pathlib import Path
import base64, zlib, json
PAYLOAD = ''
root = Path("lotofacil_axion/docs/technical-reports")
root.mkdir(parents=True, exist_ok=True)
files = json.loads(zlib.decompress(base64.b64decode(PAYLOAD)).decode("utf-8"))
for name, content in files.items():
    (root / name).write_text(content, encoding="utf-8")
readme = """# Relatórios técnicos do Modelo Axion Lotofácil

Versão 1.0 - 23 de julho de 2026.

1. [Relatório técnico nº 1 - Testes de robustez e mineração de parâmetros](relatorio_tecnico_01_robustez_mineracao_parametros.pdf)
2. [Relatório técnico nº 2 - Otimização multiobjetivo de carteiras](relatorio_tecnico_02_otimizacao_multiobjetivo_carteiras.pdf)
3. [Relatório técnico nº 3 - Limites exatos para 11+, 12+ e 13+](relatorio_tecnico_03_limites_exatos_11_12_13.pdf)
4. [Relatório técnico nº 4 - Fronteira de orçamento e eficiência marginal](relatorio_tecnico_04_fronteira_orcamento_eficiencia_marginal.pdf)

Cada PDF possui um arquivo `.sha256` e o diretório contém o manifesto `CHECKSUMS.sha256`. Os documentos são relatórios técnicos de pesquisa, não artigos científicos submetidos a periódico.
"""
(root / "README.md").write_text(readme, encoding="utf-8")
print(f"Materializados {len(files)} relatórios em {root}")
